// alarmsfx.js — owner-supplied Learjet cockpit warning alarms, appended to the
// SFX pack (like carsfx/gunsfx). Loaded AFTER soundfx.js and BEFORE game.js.
// game.js maps these via SFX_MAP: warn_stall/warn_pullup/warn_sink/warn_terrain/warn_bank.
if (typeof SFX_PACK !== "undefined") {
  SFX_PACK.warn_stall = ["data:audio/wav;base64,"];
  SFX_PACK.warn_pullup = ["data:audio/wav;base64,"];
  SFX_PACK.warn_sink = ["data:audio/wav;base64,"];
  SFX_PACK.warn_terrain = ["data:audio/wav;base64,"];
  SFX_PACK.warn_bank = ["data:audio/wav;base64,"];
}
